167	// newSymbols returns top-level FuncDecls present in the worktree (HEAD)
168	// version of each changed file but absent from the DIFF_BASE version,
169	// keyed by (file, qualified symbol name). Test files are skipped.
170	func newSymbols(projectRoot, diffBase string, files []string) ([]symbol, error) {
171		var out []symbol
172		for _, rel := range files {
173			abs := filepath.Join(projectRoot, rel)
174			newSrc, err := os.ReadFile(abs)
175			if err != nil {
176				// File deleted in HEAD — nothing to add.
177				continue
178			}
179			oldSrc, _ := gitShow(projectRoot, diffBase, rel) // empty on add
180			oldDecls := declSet(oldSrc, rel)
181			fset := token.NewFileSet()
182			f, err := parser.ParseFile(fset, abs, newSrc, parser.ParseComments)
183			if err != nil {
184				return nil, fmt.Errorf("parse %s: %w", rel, err)
185			}
186			for _, decl := range f.Decls {
187				fd, ok := decl.(*ast.FuncDecl)
188				if !ok {
189					continue
190				}
191				qn := qualName(fd)
192				if _, existed := oldDecls[qn]; existed {
193					continue
194				}
195				pos := fset.Position(fd.Pos())
196				out = append(out, symbol{
197					AbsFile:    abs,
198					Line:       pos.Line,
199					Symbol:     qn,
200					Annotation: extractPendingBead(fd),
201				})
202			}
203		}
204		return out, nil
205	}
