225	// qualName returns deadcode-style qualified name: "Func" for plain functions,
226	// "T.Method" for value-receiver methods, "(*T).Method" for pointer-receiver.
227	func qualName(fd *ast.FuncDecl) string {
228		if fd.Recv == nil || len(fd.Recv.List) == 0 {
229			return fd.Name.Name
230		}
231		recv := fd.Recv.List[0].Type
232		switch t := recv.(type) {
233		case *ast.StarExpr:
234			if id, ok := t.X.(*ast.Ident); ok {
235				return fmt.Sprintf("(*%s).%s", id.Name, fd.Name.Name)
236			}
237		case *ast.Ident:
238			return fmt.Sprintf("%s.%s", t.Name, fd.Name.Name)
239		case *ast.IndexExpr:
240			if id, ok := t.X.(*ast.Ident); ok {
241				return fmt.Sprintf("%s.%s", id.Name, fd.Name.Name)
242			}
243		case *ast.IndexListExpr:
244			if id, ok := t.X.(*ast.Ident); ok {
245				return fmt.Sprintf("%s.%s", id.Name, fd.Name.Name)
246			}
247		}
248		return fd.Name.Name
249	}
